// Node: Get Payload  (runOnceForEachItem)
const it = $input.item;
const j = it.json || {};

const src = ($items("Receber mensagem")[0] || {}).json || {};

const msg = j.messages?.[0] || src.messages?.[0] || {};
const contact = j.contacts?.[0] || src.contacts?.[0] || {};

const first = (...vals) => {
  for (const v of vals) if (typeof v === "string" && v.trim()) return v.trim();
  return "";
};

// Normaliza tudo para $json.message.content.data
const data = {
  phone: msg.from ?? contact.wa_id ?? j.phone ?? null,

  text: first(
    msg?.text?.body,
    msg?.interactive?.button_reply?.title,
    msg?.interactive?.list_reply?.title,
    msg?.button?.text,
    msg?.image?.caption,
    msg?.document?.caption
  ),

  list: {
    title: first(
      msg?.interactive?.list_reply?.title
    ) || null,
    rowId: msg?.interactive?.list_reply?.id ?? null,
  },

  button: {
    id: msg?.interactive?.button_reply?.id ?? msg?.button?.payload ?? null,
    label: msg?.interactive?.button_reply?.title ?? msg?.button?.text ?? null,
  },

  quotedMessageId: msg?.context?.id ?? null,
};

it.json.message = { content: { data } };
it.json.phone = data.phone ?? it.json.phone ?? null;

return it;

// === Formatar histórico de consumo — Run once for all items ===
const items = $input.all();

// 1) Pega as linhas do retorno da API (array no json / rows / result / data, ou vários itens)
function extractRows(arr) {
  if (!arr.length) return [];

  const j0 = arr[0].json;

  if (Array.isArray(j0)) return j0;
  if (Array.isArray(j0.rows)) return j0.rows;
  if (Array.isArray(j0.result)) return j0.result;
  if (Array.isArray(j0.data)) return j0.data;

  // NOVO:
  // Se veio apenas 1 item simples, transforma em array
  if (arr.length === 1) {
    return [j0];
  }

  // vários itens
  if (arr.length > 1) {
    return arr.map(i => i.json);
  }

  return [];
}
const rows = extractRows(items);

// 2) Utilitários
const pad  = (s, w) => String(s ?? '').padEnd(w, ' ');
const padR = (s, w) => String(s ?? '').padStart(w, ' ');
const numBR = (n) => Number(n ?? 0).toLocaleString('pt-BR');

// 3) Phone / sessão / ligação
const respostaLista = $("Resposta lista").first().json || {};

const phone =
  respostaLista.phone ??
  respostaLista.session?.phone ??
  respostaLista._session?.phone ??
  null;

const session =
  respostaLista.session ??
  respostaLista._session ??
  null;

const ligacao = $('Router').first().json._session.data_json.codigoLigacao ?? '';

// 4) Sem dados → resposta amigável
if (!rows.length) {
  return [{
    json: {
      phone,
      session,
      ligacao,
      reply: 'Não encontrei histórico de consumo para a ligação *' + ligacao + '*\n'
    },
    pairedItem: [{ item: 0 }]
  }];
}

// 5) Mapeia e formata (API: referencia, leitura, litrosConsumidos, valorFaturado, vencimento)
const mapped = rows.map(r => ({
  referencia:   String(r.referencia ?? ''),
  leitura:   String(r.leitura ?? ''),
  consumo:String(r.litrosConsumidos ?? 0),
}));

// 6) Tabela monoespaçada
const W_MES=10, W_LEI=8, W_CONS=8;
const header = `${pad('Mês/Ano', W_MES)} ${pad('Leitura', W_LEI)} ${pad('Consumo', W_CONS)}`;
const sep    = '-'.repeat(header.length);

const lines = mapped.map(r =>
  `${pad(r.referencia, W_MES-2)} ${padR(numBR(r.leitura), W_LEI)} ${padR(numBR(r.consumo), W_CONS)}`
);

const reply =
  `📊 Histórico de consumo da ligação *` + ligacao + `*\n` +
  '```' + '\n' +
  header + '\n' + sep + '\n' +
  lines.join('\n') + '\n' + sep + '\n' +
  '```';

// 7) Saída única para o HTTP /send-text
return [{
  json: { phone, session, reply },
  // devolve pairedItem p/ evitar erros de "Paired item data..."
  pairedItem: [{ item: 0 }]
}];

const it = $input.item;
const j  = it.json;

// phone
const phone =
  j.session?.phone ??
  j._session?.phone ??
  j.body?.phone ??
  j.phone ??
  $items("Receber mensagem")[0]?.json?.body?.phone ??
  null;

// phone
const phoneconectado =
  j.session?.phoneconectado ??
  j._session?.phoneconectado ??
  j.body?.phoneconectado ??
  j.phoneconectado ??
  $items("Receber mensagem")[0]?.json?.body?.phoneconectado ??
  null;

// data_json pode ser string
let dj = $("Autenticado ?").first().json.data_json;
if (typeof dj === 'string') { try { dj = JSON.parse(dj); } catch { dj = {}; } }
dj = dj || {};

j.session = {
  phone,
  flow: "confirm",
  step: 1,
  expectedRef: j.session?.expectedRef ?? null,
  data: {
    // mantém plano
    authOk: true,
    nome: dj.nome ?? j.session?.data?.nome ?? '',
    codigoLigacao: dj.codigoLigacao ?? j.session?.data?.codigoLigacao ?? null,
  },
  // expiresAt é da sessão, não de data
  expiresAt: new Date(Date.now() + 15 * 60000).toISOString(),
  phoneconectado,
};

return it; // (antes retornava j; mantenha o item inteiro)

const item = $input.item;
const j = item.json;

const phone =
  j.session?.phone ??
  j.phone ??
  $items("Receber mensagem")[0]?.json?.body?.phone ?? null;

// guarda a sessão COMPLETA; não altere o item
j._snapList = {
  phone,
  session: JSON.parse(JSON.stringify(j.session || {})),
};

return item;

const item = $input.item || {};
const receberMensagem = $("Receber mensagem").first().json || {};

const j = {
  ...(item.json || {}),
  ...receberMensagem
};

// === PHONE ===
const rxPhone =
  j.phone ??
  j.contacts?.[0]?.wa_id ??
  j.messages?.[0]?.from ??
  null;

// === PHONE CONECTADO ===
const rxPhoneconectado =
  j.phoneconectado ??
  j.metadata?.display_phone_number ??
  null;

// === APLICA ===
j.phone = rxPhone;
j.phoneconectado = rxPhoneconectado;

// === SESSION ===
j.session = j.session || {};

j.session.phone = j.session.phone ?? rxPhone;
j.session.phoneconectado = j.session.phoneconectado ?? rxPhoneconectado;
j.session.flow = "confirm";
j.session.step = 1;
j.session.data = j.session.data || {};
j.session.expiresAt = new Date(Date.now() + 15 * 60000).toISOString();

// === RESPOSTA ===
j.reply = "Posso lhe ajudar em algo mais?";

// === BOTÕES API OFICIAL ===
j.interactive = {
  type: "button",
  body: {
    text: j.reply
  },
  action: {
    buttons: [
      {
        type: "reply",
        reply: {
          id: "Sim",
          title: "Sim"
        }
      },
      {
        type: "reply",
        reply: {
          id: "Não",
          title: "Não"
        }
      }
    ]
  }
};

return {
  json: j
};

// não destrói o payload; só guarda uma cópia da sessão para o Merge pós-HTTP
const item = $input.item;
const j = item.json;

j._snap = { phone: j.phone, session: j.session }; // stash para uso no Set expectedRef / Merge
return item; // mantém reply, showMenu, etc.

return [
  {
    json: {
      phone: $json.phone,
      session: $json.session,
    },
  },
];

/**
 * ROUTER — WhatsApp Cloud API Oficial
 * Compatível com estrutura antiga da Z-API
 */

const item = $input.item || { json: {} };
const j = item.json || {};

// ===================== NORMALIZA CLOUD API =====================

const cloudMsg =
  Array.isArray(j.messages)
    ? j.messages[0]
    : j.entry?.[0]?.changes?.[0]?.value?.messages?.[0] || null;

const cloudValue =
  Array.isArray(j.messages)
    ? j
    : j.entry?.[0]?.changes?.[0]?.value || {};

if (cloudMsg) {
  const msg = cloudMsg;
  const contact = cloudValue.contacts?.[0] || j.contacts?.[0] || {};
  const metadata = cloudValue.metadata || j.metadata || {};
  const type = msg.type || "";

  let text = "";
  let button = null;
  let list = null;
  let image = null;
  let audio = null;
  let document = null;

  if (type === "text") {
    text = msg.text?.body || "";
  }

  if (type === "button") {
    button = {
      label: msg.button?.text || "",
      id: msg.button?.payload || "",
    };
    text = button.label;
  }

  if (type === "interactive") {
    if (msg.interactive?.type === "button_reply") {
      button = {
        label: msg.interactive.button_reply?.title || "",
        id: msg.interactive.button_reply?.id || "",
      };
      text = button.label;
    }

    if (msg.interactive?.type === "list_reply") {
      list = {
        title: msg.interactive.list_reply?.title || "",
        rowId: msg.interactive.list_reply?.id || "",
      };
      text = list.title;
    }
  }

  if (type === "image") {
    image = {
      id: msg.image?.id || "",
      mime_type: msg.image?.mime_type || "",
      sha256: msg.image?.sha256 || "",
      caption: msg.image?.caption || "",
    };
    text = msg.image?.caption || "";
  }

  if (type === "audio") {
    audio = {
      id: msg.audio?.id || "",
      mime_type: msg.audio?.mime_type || "",
      sha256: msg.audio?.sha256 || "",
      voice: msg.audio?.voice || false,
    };
  }

  if (type === "document") {
    document = {
      id: msg.document?.id || "",
      filename: msg.document?.filename || "",
      mime_type: msg.document?.mime_type || "",
      sha256: msg.document?.sha256 || "",
      caption: msg.document?.caption || "",
    };
    text = msg.document?.caption || "";
  }

  const phone = msg.from || contact.wa_id || "";
  const chatName = contact.profile?.name || "";
  const phoneconectado = metadata.display_phone_number || "";
  const phoneNumberId = metadata.phone_number_id || "";

  j.body = {
    ...(j.body || {}),
    phone,
    from: phone,
    chatName,
    fromMe: false,
    isGroup: false,
    messageId: msg.id || "",
    timestamp: msg.timestamp || "",
    type,
    phoneconectado,
    connectedPhone: phoneconectado,
    phoneNumberId,
    text: {
      message: text,
    },
    button,
    list,
    image,
    audio,
    document,
  };

  j.message = {
    ...(j.message || {}),
    content: {
      ...(j.message?.content || {}),
      data: {
        text,
        phone,
        chatName,
        button,
        list,
        image,
        audio,
        document,
        type,
      },
    },
  };

  j.phone = j.phone ?? phone;
  j.chatName = j.chatName ?? chatName;
  j.messageId = j.messageId ?? msg.id;
  j.messageText = j.messageText ?? text;
  j.phoneconectado = j.phoneconectado ?? phoneconectado;
  j.phoneNumberId = j.phoneNumberId ?? phoneNumberId;
}

// ===================== UTILS =====================

const first = (...vals) => {
  for (const v of vals) {
    if (typeof v === "string" && v.trim() !== "") return v.trim();
  }
  return "";
};

const lower = (s) => (s || "").toLowerCase();

// ===================== ENTRADA =====================

const data = j?.message?.content?.data || {};

const textIn = first(data.text, j?.body?.text?.message, j?.messageText);

const listT = data?.list?.title || j?.body?.list?.title || null;
const listId = data?.list?.rowId || j?.body?.list?.rowId || null;
const btnLabel = data?.button?.label || j?.body?.button?.label || null;

j.isList = !!(listT || listId);
j.choiceTitle = listT;
j.choiceId = listId;
j.showEnd = false;

let msg = j.isList ? j.choiceTitle || "" : textIn;
if (!msg && btnLabel) msg = btnLabel;

const normalized = String(msg).trim().toLowerCase();

// ===================== SAIR =====================

if (normalized.includes("sair")) {
  j.showEnd = true;
  j.reply = "*Atendimento finalizado* 😊\nObrigado pelo contato!";
  return item;
}

// ===================== PHONE =====================

j.phone =
  j.phone ??
  j?.body?.phone ??
  data?.phone ??
  j?.messages?.[0]?.from ??
  j?.contacts?.[0]?.wa_id ??
  null;

// ===================== SESSÃO =====================

const row = j._session || {};
let session = null;

if (row && (row.flow || row.data_json || row.expires_at)) {
  session = {
    phone: row.phone || j.phone,
    phoneconectado: row.phoneconectado || j.phoneconectado,
    flow: row.flow || "ident",
    step: Number(row.step ?? 1),
    expectedRef: row.expected_ref ?? row.expectedRef ?? null,
    data: row.data_json
      ? typeof row.data_json === "string"
        ? JSON.parse(row.data_json || "{}") || {}
        : row.data_json
      : {},
    expiresAt: row.expires_at ? new Date(row.expires_at).toISOString() : null,
  };
}

if (session?.expiresAt && new Date(session.expiresAt) < new Date()) {
  session = null;
}

const low = lower(msg);

if (low === "menu" || low === "cancelar") {
  session = null;
}

// ===================== IDENTIFICAÇÃO =====================

const authed = session?.data?.authOk === true;

const msgDefault =
  j.phoneconectado == "558888856714"
    ? "👋🏻 Olá! Eu sou a *SARA*.\nPara começarmos, qual é o seu *nome*?"
    : "👋🏻 Olá! Eu sou o *BILL*, seu assistente virtual.\nPara começarmos, qual é o seu *nome*?";

if (!authed) {
  if (!session || session.flow !== "ident") {
    session = {
      phone: j.phone,
      phoneconectado: j.phoneconectado,
      flow: "ident",
      step: 1,
      data: {},
      expectedRef: null,
      expiresAt: new Date(Date.now() + 60 * 60000).toISOString(),
    };

    j.reply = msgDefault;
    j.finalize = false;
  }

  else if (session.step === 1 && !j.reply) {
    if (msg === "") {
      j.reply =
        "Desculpe, não consegui entender.\nPode me informar seu *nome*, por favor? 🙌🏻";
    } else {
      session.data.nome = msg;
      session.step = 2;
      session.needValidateLigacao = false;

      j.reply = `Prazer, *${session.data.nome}* 👋🏻\nAgora me informe o *código da ligação* usando apenas números.\n\nSe quiser sair do atendimento, digite *Sair*.`;
    }

    j.finalize = false;
  }

  else if (session.step === 2 && !j.reply) {
    const codigodaLigacao = String(msg ?? "").trim();

    if (codigodaLigacao === "") {
      j.reply = "Informe o *código da ligação*.";
      j.finalize = false;
    }

    else if (!/^[0-9]+$/.test(codigodaLigacao)) {
      j.reply =
        "O código informado não é válido.\n\nDigite apenas os *números*, sem letras, espaços ou símbolos. 🔢";
      j.finalize = false;
    }

    else {
      session.data.codigoLigacao = codigodaLigacao;

      if (j.phoneconectado == "558888856714") {
        session.data.chavedigital = "";
        session.step = 3;
        session.needValidateLigacao = true;
        j.reply = null;
        j.finalize = false;
      } else {
        session.step = 3;
        session.needValidateLigacao = false;
        j.reply = `*${session.data.nome}*, me informe por favor a *chave digital*.`;
        j.finalize = false;
      }
    }
  }

  else if (session.step === 3 && !j.reply) {
    const chavedigital = String(msg ?? "").trim();

    if (chavedigital === "") {
      j.reply = "Informe a *chave digital*.";
      j.finalize = false;
    } else {
      session.data.chavedigital = chavedigital;
      session.needValidateLigacao = true;
      j.reply = null;
      j.finalize = false;
    }
  }

  session.expiresAt = new Date(Date.now() + 60 * 60000).toISOString();

  j.session = {
    phone: session.phone,
    phoneconectado: session.phoneconectado,
    flow: session.flow,
    step: session.step,
    expectedRef: session.expectedRef,
    data: session.data,
    expiresAt: session.expiresAt,
    needValidateLigacao: !!session.needValidateLigacao,
  };

  return item;
}

// ===================== AUTENTICADO =====================

const ans = lower(btnLabel || j.choiceTitle || msg || "");
const isYesNo = ans === "sim" || ans === "não";

if (session?.flow === "humano") {
  session.flow = "ident";
  session.step = 3;
  session.needValidateLigacao = true;
  j.reply = null;
}

if (session?.flow === "confirm" && session?.step === 1 && isYesNo) {
  if (ans === "sim") {
    session.step = 0;
    j.showMenu = true;
    j.reply = "";
  } else {
    session.step = 0;
    j.showEnd = true;
    j.reply = "Certo, atendimento finalizado 😊\nObrigado pelo contato!";
  }

  session.expiresAt = new Date(Date.now() + 60 * 60000).toISOString();
  j.session = session;

  return item;
}

// ===================== ESCOLHA DE SERVIÇO =====================

const chosen = lower(j.isList ? j.choiceTitle : msg || "");

if (chosen === "localização") {
  j.reply = null;
}

else if (chosen.includes("denúncia") || chosen.includes("denuncia")) {
  j.reply =
    "Tudo certo! 💬\n\nMe conte com o máximo de detalhes o que aconteceu.";
  session.flow = "ouvidoria";
}

else if (
  chosen === "histórico de consumo" ||
  chosen === "historico de consumo"
) {
  j.reply = null;
}

else if (
  chosen === "2ª via de fatura" ||
  chosen === "2ª via" ||
  chosen === "faturas em aberto"
) {
  j.reply = null;
}

// ===================== ATUALIZA SESSÃO =====================

session.expiresAt = new Date(Date.now() + 60 * 60000).toISOString();

j.session = {
  phone: session.phone,
  phoneconectado: session.phoneconectado,
  flow: session.flow,
  step: session.step,
  expectedRef: session.expectedRef,
  data: session.data,
  expiresAt: session.expiresAt,
  needValidateLigacao: !!session.needValidateLigacao,
};

return item;

const j = $input.item.json;
const sess = j.session || {};
sess.data = sess.data || {};

let codigo = String(sess.data.codigoLigacao ?? j.codigo ?? '').trim();
codigo = (codigo.match(/\d+/g)?.join('')) || '';
if (codigo) sess.data.codigoLigacao = codigo;
else delete sess.data.codigoLigacao;

return [{ json: { phone: j.phone, session: sess } }];

// -------- Processa Validação (após MERGE) --------
const j = $input.item.json || {};
const sess = j.session || {};
const phone = j.phone || sess.phone || null;

const found = Number(j.found ?? j.matricula != null) === 1;
const nome = sess?.data?.nome || "cliente";
const codigo = sess?.data?.codigoLigacao || j.codigo || "";

if (found) {
  sess.data = sess.data || {};
  sess.data.authOk = true;
  sess.flow = "menu";
  sess.step = 0;
  sess.needValidateLigacao = false;
  sess.expiresAt = new Date(Date.now() + 60 * 60000).toISOString();
  sess.data.codigoLigacao = codigo;
  sess.data.nome = nome;

const cab = `Tudo certo, *` + nome + `*!✅\n\nValidei a ligação *` + codigo + `*.\n\nEsta ligação está vinculada ao endereço : *` + $input.first().json.rua + `*, número *XXX*, *` + $input.first().json.bairro + `*.\n\nQue bom ter você por aqui !\nEm que posso lhe ajudar ?`;
  return [{ json: { phone, session: sess, showMenu: true, reply: cab } }];
}

// NÃO ENCONTROU → sempre devolve texto
sess.step = 2;
sess.needValidateLigacao = true;
sess.expiresAt = new Date(Date.now() + 60 * 60000).toISOString();

const msg =
  "Não consegui validar os dados informados.\n\nPor favor, digite novamente o *código da ligação* (apenas os números, sem o dígito). 🔁";
return [{ json: { phone, session: sess, showMenu: false, reply: msg } }];

const item = $input.item;
const j = item.json;

// ==== ENTRADA / CAMPOS ÚTEIS (mantidos) ====
const b = j.body ?? {};
j.phone = j.Phone ?? b.Phone ?? null;

// veio resposta de lista/botão?
j.listResponse = !!(b.listResponseMessage || b.listResponse || b.buttonReply);

// flag “encerrar atendimento” quando clicado em “Não”
const btnMsg = (b?.buttonReply?.message ?? "").trim().toLowerCase();
j.encerraratendimento = btnMsg === "não";

// ==== CONFIGURAÇÃO POR NÚMERO (adicione seus números aqui) ====
// Use apenas dígitos no índice, exatamente como chega em j.PhoneConnected
const phonesConfig = {
  553799846521: {
    acessToken: "3EA6B3979B12E1B6EDC772620DC9C8F4",
    businessAccountID: "1512857447000297",
    rotaPrincipalDados:
      "https://tdev3-ag.icommercial002.inovamobil.com.br/api/chatbot",
    title: "Inovação Computação Móvel",
    address: "Avenida Paraná, 1348, Sidil, Divinopolis, MG, 35501-660",
    lat: "-20.135580",
    long: "-44.896239",
    tipoRequerimento: 54,
  },
};

// ==== OBRIGATÓRIO TER PhoneConnected ====
const phoneConnected = (j.PhoneConnected ?? "").replace(/\D+/g, "");
const selected = phonesConfig[phoneConnected];
if (!selected) {
  throw new Error(
    `PhoneConnected (${phoneConnected || "vazio"}) não mapeado em phonesConfig`,
  );
}

// ==== PARAMS (nomes mantidos, sem impacto) ====
const AcessToken = selected.acessToken;
const BusinessAccountID = selected.businessAccountID;
const rotaPrincipalDados = selected.rotaPrincipalDados;

j.api = {
  rotaPrincipalDados,
  endpoints: {
    historicoConsumo: `${rotaPrincipalDados}/historico-consumo`,
    ultimasFaturas: `${rotaPrincipalDados}/faturas-abertas`,
    faturasPagas: `${rotaPrincipalDados}/faturas-concluidas`,
    retornarUsuario: `${rotaPrincipalDados}/retornar-usuario`,
    gerarFatura: `${rotaPrincipalDados}/fatura-pdf`,
    ouvidoria: `${rotaPrincipalDados}/denuncia`,
    auditoria: `${rotaPrincipalDados}/auditoria`,
  },
  location: {
    title: selected.title,
    address: selected.address,
    lat: selected.lat,
    long: selected.long,
  },
  configuracao: {
    tipoRequerimento: selected.tipoRequerimento,
    HorarioAtendimentoHumanoInicio : "08:00",
    HorarioAtendimentoHumanoFim : "17:00"
  },
};

return item;

// NORMALIZADOR DE CLIQUE — WhatsApp Cloud API Oficial

const msg = $json.messages?.[0] || {};
const interactive = msg.interactive || {};

const id =
  interactive?.list_reply?.id ||
  interactive?.button_reply?.id ||
  "";

const isInvoiceClickAbertas =
  /^fat_sel_/.test(id);

const isActionClickAbertas =
  /^fat_act_/.test(id);

