// Recupera as configurações vindas do nó "Constantes"
const cfg = $('Constantes').item.json.env.api.configuracao || {};

// Lê os horários de início e fim em string ("HH:mm")
const iniStr = String(cfg.HorarioAtendimentoHumanoInicio || '').trim();
const fimStr = String(cfg.HorarioAtendimentoHumanoFim || '').trim();

// Retorno padrão (fora do horário)
let dentroDoHorario = false;

if (/^\d{2}:\d{2}$/.test(iniStr) && /^\d{2}:\d{2}$/.test(fimStr)) {
  const [hI, mI] = iniStr.split(':').map(Number);
  const [hF, mF] = fimStr.split(':').map(Number);

  // Hora atual de Brasília
  const agoraBR = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
  const minutosAgora = agoraBR.getHours() * 60 + agoraBR.getMinutes();

  const ini = hI * 60 + mI;
  const fim = hF * 60 + mF;

  if (ini <= fim) {
    // Janela normal (mesmo dia)
    dentroDoHorario = minutosAgora >= ini && minutosAgora < fim;
  } else {
    // Janela que cruza a meia-noite (ex: 22:00–06:00)
    dentroDoHorario = minutosAgora >= ini || minutosAgora < fim;
  }
}

return [{
  json: {
    dentroDoHorario: Boolean(dentroDoHorario)
  }
}];

